const input = $json;
const clean = (value) => value === undefined || value === null ? '' : String(value).trim();
const body = {};
const apiKey = clean(input.api_key);
function put(name, label, type, required) {
  const value = clean(input[label]);
  if (!value && !required) return;
  if (type === "number") { const n = Number(value); if (!Number.isNaN(n)) body[name] = n; return; }
  if (type === "boolean") { body[name] = value === "true" || value === "1" || value.toLowerCase() === "yes"; return; }
  body[name] = value;
}
put("prompt", "prompt", "string", true);
put("model", "model [optional]", "string", false);
put("duration", "duration [optional]", "number", false);
if (body["model"] === undefined || body["model"] === '') body["model"] = "normal";
const arr0 = ["image_url_1 [optional]","image_url_2 [optional]","image_url_3 [optional]","image_url_4 [optional]"].map(label => clean(input[label])).filter(Boolean);
if (arr0.length) body["images"] = arr0;
body.tag = clean(input['tag [optional]']) || "n8n-grok-imagine";
return [{ json: { api_key: apiKey, body } }];
